package com.hr.security;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPEnvelope;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPFault;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import javax.xml.ws.soap.SOAPFaultException;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.Collections;
import java.util.Iterator;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

public class AuthenticationHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(AuthenticationHandler.class.getName());
    private static final String AUTH_NS = "http://hr.com/security";
    private static final String AUTH_HEADER = "AuthHeader";

    // In production, use a proper credential store / LDAP / database
    private static final Map<String, String> AUTHORIZED_USERS = new ConcurrentHashMap<>();

    static {
        // Stored as hashed passwords (SHA-256)
        AUTHORIZED_USERS.put("hr_admin", hashPassword("secureAdminPass!2024"));
        AUTHORIZED_USERS.put("hr_manager", hashPassword("secureManagerPass!2024"));
    }

    private static String hashPassword(String password) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(password.getBytes(StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }

    @Override
    public Set<QName> getHeaders() {
        return Collections.singleton(new QName(AUTH_NS, AUTH_HEADER));
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (outbound != null && outbound) {
            return true; // Don't process outbound messages
        }

        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                LOGGER.warning("Authentication failed: No SOAP header present");
                generateSOAPFault(message, "Authentication required");
                return false;
            }

            String username = null;
            String password = null;

            Iterator<?> it = header.getChildElements(new QName(AUTH_NS, AUTH_HEADER));
            if (it.hasNext()) {
                javax.xml.soap.SOAPElement authElement = (javax.xml.soap.SOAPElement) it.next();
                Iterator<?> children = authElement.getChildElements();
                while (children.hasNext()) {
                    javax.xml.soap.SOAPElement child = (javax.xml.soap.SOAPElement) children.next();
                    String localName = child.getLocalName();
                    if ("Username".equals(localName)) {
                        username = child.getTextContent();
                    } else if ("Password".equals(localName)) {
                        password = child.getTextContent();
                    }
                }
            }

            if (username == null || password == null) {
                LOGGER.warning("Authentication failed: Missing credentials");
                generateSOAPFault(message, "Authentication credentials required");
                return false;
            }

            // Validate input
            if (!isValidInput(username) || !isValidInput(password)) {
                LOGGER.warning("Authentication failed: Invalid input format");
                generateSOAPFault(message, "Invalid credentials format");
                return false;
            }

            String storedHash = AUTHORIZED_USERS.get(username);
            if (storedHash == null || !storedHash.equals(hashPassword(password))) {
                LOGGER.warning("Authentication failed for user: " + sanitizeLogInput(username));
                generateSOAPFault(message, "Invalid credentials");
                return false;
            }

            // Store authenticated user in context for authorization checks
            context.put("authenticated.user", username);
            context.setScope("authenticated.user", MessageContext.Scope.APPLICATION);

            LOGGER.info("User authenticated successfully: " + sanitizeLogInput(username));
            return true;

        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error processing authentication", e);
            return false;
        }
    }

    private boolean isValidInput(String input) {
        return input != null && input.length() <= 128 && input.matches("[a-zA-Z0-9_!@#$%^&*]+");
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[^a-zA-Z0-9_]", "*");
    }

    private void generateSOAPFault(SOAPMessage message, String reason) {
        try {
            SOAPBody body = message.getSOAPPart().getEnvelope().getBody();
            SOAPFault fault = body.addFault();
            fault.setFaultString(reason);
            throw new SOAPFaultException(fault);
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error generating SOAP fault", e);
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

