package com.hr.security;

import com.hr.exception.HRServiceException;
import java.util.regex.Pattern;

public class InputValidator {

    private static final Pattern EMPLOYEE_ID_PATTERN = Pattern.compile("^EMP[0-9]{4,10}$");
    private static final Pattern NAME_PATTERN = Pattern.compile("^[a-zA-Z\\s\\-']{1,100}$");
    private static final Pattern DEPARTMENT_PATTERN = Pattern.compile("^[a-zA-Z\\s\\-]{1,50}$");
    private static final Pattern RATING_PATTERN = Pattern.compile("^(EXCEEDS|MEETS|BELOW|UNSATISFACTORY)$");
    private static final Pattern REVIEW_ID_PATTERN = Pattern.compile("^REV[0-9]{4,10}$");
    private static final Pattern REVIEW_PERIOD_PATTERN = Pattern.compile("^(Q[1-4]|H[1-2]|ANNUAL)-[0-9]{4}$");
    private static final double MAX_SALARY = 10000000.0;
    private static final double MIN_SALARY = 0.0;
    private static final int MAX_COMMENT_LENGTH = 2000;

    public static void validateEmployeeId(String employeeId) throws HRServiceException {
        if (employeeId == null || !EMPLOYEE_ID_PATTERN.matcher(employeeId).matches()) {
            throw new HRServiceException("Invalid employee ID format. Expected: EMP followed by 4-10 digits", "INVALID_INPUT");
        }
    }

    public static void validateName(String name, String fieldName) throws HRServiceException {
        if (name == null || !NAME_PATTERN.matcher(name).matches()) {
            throw new HRServiceException("Invalid " + fieldName + " format", "INVALID_INPUT");
        }
    }

    public static void validateDepartment(String department) throws HRServiceException {
        if (department == null || !DEPARTMENT_PATTERN.matcher(department).matches()) {
            throw new HRServiceException("Invalid department format", "INVALID_INPUT");
        }
    }

    public static void validateSalary(double salary) throws HRServiceException {
        if (salary < MIN_SALARY || salary > MAX_SALARY || Double.isNaN(salary) || Double.isInfinite(salary)) {
            throw new HRServiceException("Invalid salary amount. Must be between 0 and 10,000,000", "INVALID_INPUT");
        }
    }

    public static void validateRating(String rating) throws HRServiceException {
        if (rating == null || !RATING_PATTERN.matcher(rating).matches()) {
            throw new HRServiceException("Invalid rating. Must be: EXCEEDS, MEETS, BELOW, or UNSATISFACTORY", "INVALID_INPUT");
        }
    }

    public static void validateReviewId(String reviewId) throws HRServiceException {
        if (reviewId == null || !REVIEW_ID_PATTERN.matcher(reviewId).matches()) {
            throw new HRServiceException("Invalid review ID format. Expected: REV followed by 4-10 digits", "INVALID_INPUT");
        }
    }

    public static void validateReviewPeriod(String period) throws HRServiceException {
        if (period == null || !REVIEW_PERIOD_PATTERN.matcher(period).matches()) {
            throw new HRServiceException("Invalid review period format. Expected: Q1-2024, H1-2024, or ANNUAL-2024", "INVALID_INPUT");
        }
    }

    public static void validateComments(String comments) throws HRServiceException {
        if (comments != null && comments.length() > MAX_COMMENT_LENGTH) {
            throw new HRServiceException("Comments exceed maximum length of " + MAX_COMMENT_LENGTH, "INVALID_INPUT");
        }
    }

    public static String sanitizeString(String input) {
        if (input == null) return null;
        return input.trim()
                .replaceAll("[<>\"'&]", "")
                .replaceAll("\\s+", " ");
    }
}

