package com.hr.repository;

import com.hr.model.Employee;
import com.hr.model.PerformanceReview;

import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

public class EmployeeRepository {

    private static final Logger LOGGER = Logger.getLogger(EmployeeRepository.class.getName());
    private static final Map<String, Employee> employees = new ConcurrentHashMap<>();
    private static final Map<String, List<PerformanceReview>> reviews = new ConcurrentHashMap<>();

    static {
        // Sample data
        Employee emp1 = new Employee("EMP0001", "John", "Doe", "Engineering", 95000.0);
        Employee emp2 = new Employee("EMP0002", "Jane", "Smith", "Marketing", 85000.0);
        Employee emp3 = new Employee("EMP0003", "Bob", "Johnson", "Finance", 90000.0);
        employees.put(emp1.getEmployeeId(), emp1);
        employees.put(emp2.getEmployeeId(), emp2);
        employees.put(emp3.getEmployeeId(), emp3);
    }

    public Employee findById(String employeeId) {
        return employees.get(employeeId);
    }

    public boolean exists(String employeeId) {
        return employees.containsKey(employeeId);
    }

    public void save(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
        LOGGER.info("Employee saved: " + employee.getEmployeeId());
    }

    public void addReview(PerformanceReview review) {
        reviews.computeIfAbsent(review.getEmployeeId(), k -> new ArrayList<>()).add(review);
        LOGGER.info("Review added for employee: " + review.getEmployeeId());
    }

    public List<PerformanceReview> getReviews(String employeeId) {
        return reviews.getOrDefault(employeeId, new ArrayList<>());
    }

    public List<Employee> findAll() {
        return new ArrayList<>(employees.values());
    }
}

