// ============================================================
// web.xml - Deployment descriptor (key security sections)
// ============================================================
/*
<?xml version="1.0" encoding="UTF-8"?>
<web-app xmlns="http://xmlns.jcp.org/xml/ns/javaee"
         xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
         xsi:schemaLocation="http://xmlns.jcp.org/xml/ns/javaee
         http://xmlns.jcp.org/xml/ns/javaee/web-app_3_1.xsd"
         version="3.1">

    <display-name>HR Employee Management Service</display-name>

    <!-- Enforce HTTPS transport -->
    <security-constraint>
        <web-resource-collection>
            <web-resource-name>HR Services</web-resource-name>
            <url-pattern>/services/*</url-pattern>
        </web-resource-collection>
        <user-data-constraint>
            <transport-guarantee>CONFIDENTIAL</transport-guarantee>
        </user-data-constraint>
    </security-constraint>

    <!-- Filter ordering -->
    <filter>
        <filter-name>TransportSecurityFilter</filter-name>
        <filter-class>com.hr.security.TransportSecurityFilter</filter-class>
    </filter>
    <filter-mapping>
        <filter-name>TransportSecurityFilter</filter-name>
        <url-pattern>/services/*</url-pattern>
    </filter-mapping>

    <filter>
        <filter-name>WsdlAccessFilter</filter-name>
        <filter-class>com.hr.security.WsdlAccessFilter</filter-class>
    </filter>
    <filter-mapping>
        <filter-name>WsdlAccessFilter</filter-name>
        <url-pattern>/services/*</url-pattern>
    </filter-mapping>

    <!-- Error pages - prevent information leakage -->
    <error-page>
        <error-code>404</error-code>
        <location>/error/notfound.html</location>
    </error-page>
    <error-page>
        <error-code>500</error-code>
        <location>/error/servererror.html</location>
    </error-page>
    <error-page>
        <exception-type>java.lang.Throwable</exception-type>
        <location>/error/servererror.html</location>
    </error-page>
</web-app>
*/

// ============================================================
// HRServicePublisher.java - Standalone endpoint publisher
// (For development/testing only; production uses app server)
// ============================================================
package com.hr;

import com.hr.security.HRHandlerResolver;
import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import javax.xml.ws.soap.SOAPBinding;
import java.util.logging.Logger;

public class HRServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(HRServicePublisher.class.getName());

    /**
     * Publishes the HR service endpoint.
     * 
     * SECURITY NOTES:
     * - In production, deploy behind a reverse proxy with TLS termination
     * - Use HTTPS endpoint URL (requires SSL configuration)
     * - The WSDL is restricted by WsdlAccessFilter in servlet container deployments
     * - For standalone Endpoint.publish(), WSDL is available at the URL + ?wsdl
     *   so this should ONLY be used on internal/loopback interfaces
     */
    public static void main(String[] args) {
        // Bind to loopback only - prevents external WSDL access in standalone mode
        String bindAddress = "https://127.0.0.1:8443/services/EmployeeManagement";

        try {
            EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
            Endpoint endpoint = Endpoint.create(SOAPBinding.SOAP12HTTP_BINDING, serviceImpl);

            // Configure properties to limit metadata exposure
            java.util.Map<String, Object> properties = new java.util.HashMap<>();
            // Disable WSDL publication in standalone mode for security
            // Clients should use a pre-shared WSDL file instead
            properties.put("javax.xml.ws.wsdl.description", null);
            endpoint.setProperties(properties);

            LOGGER.info("Starting HR Employee Management Service...");
            LOGGER.info("Binding to loopback interface only: " + bindAddress);
            LOGGER.warning("STANDALONE MODE: For production, deploy in a servlet container with TLS and WsdlAccessFilter");

            endpoint.publish(bindAddress);

            LOGGER.info("HR Employee Management Service is running");
            LOGGER.info("Service requires authentication via SOAP header");
            LOGGER.info("Press Ctrl+C to stop the service");

            // Add shutdown hook
            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                LOGGER.info("Shutting down HR Service...");
                endpoint.stop();
                LOGGER.info("HR Service stopped");
            }));

        } catch (Exception e) {
            LOGGER.severe("Failed to start HR Service: " + e.getMessage());
            System.exit(1);
        }
    }
}